# FTRL-Proximal: Follow The Regularized Leader
# Handles 10B+ sparse features with per-coordinate learning rates

import numpy as np

class FTRLProximal:
    def __init__(self, alpha=0.1, beta=1.0, L1=1.0, L2=1.0):
        self.alpha = alpha  # learning rate parameter
        self.beta = beta     # smoothing parameter
        self.L1 = L1         # L1 regularization (pushes weights to zero)
        self.L2 = L2         # L2 regularization
        self.z = {}          # weight accumulator
        self.n = {}          # learning rate accumulator

    def predict(self, x):
        """x is a dict of {feature_index: value} sparse representation"""
        w = {}
        for idx in x:
            sign = -1 if self.z.get(idx, 0) < 0 else 1
            if abs(self.z.get(idx, 0)) <= self.L1:
                w[idx] = 0.0
            else:
                w[idx] = (sign * self.L1 - self.z[idx]) / (
                    (self.beta + np.sqrt(self.n.get(idx, 0))) / self.alpha + self.L2
                )
        logit = sum(w.get(idx, 0) * val for idx, val in x.items())
        return 1.0 / (1.0 + np.exp(-np.clip(logit, -20, 20)))

    def update(self, x, p, y):
        """Online update with per-coordinate learning rate"""
        grad = p - y  # logistic loss gradient
        for idx, val in x.items():
            sigma = (np.sqrt(self.n.get(idx, 0) + grad**2) -
                     np.sqrt(self.n.get(idx, 0))) / self.alpha
            self.z[idx] = self.z.get(idx, 0) + grad * val - sigma * self.get_w(idx)
            self.n[idx] = self.n.get(idx, 0) + grad**2

import numpy as np
from typing import Dict, Tuple

class ModerationPipeline:
    def __init__(self):
        self.blocklist = set()  # T1 heuristics
        self.text_model = None  # T2 shallow text classifier
        self.image_model = None  # T3 deep image model
        self.human_queue = []   # T4 human review queue

    def classify(self, content: Dict) -> Tuple[str, float]:
        """Returns (action, confidence). Actions: allow, flag, review"""
        # T1: Fast heuristics
        if content['text'] in self.blocklist:
            return ('block', 1.0)
        # T2: Shallow model (<50ms)
        score = self._t2_score(content)
        if score < 0.1:
            return ('allow', 1.0 - score)
        if score > 0.9:
            return ('block', score)
        # T3: Deep model (<500ms)
        score = self._t3_score(content)
        if score > 0.95:
            return ('block', score)
        if 0.7 < score < 0.95:
            return ('review', score)  # Send to human review
        return ('allow', 1.0 - score)
